1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return empty set when given empty set", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill cells with only one live neighbor (underpopulation)", () => {
12	    expect(nextGeneration(new Set(["0,0", "1,0"]))).toEqual(new Set());
13	  });
14	  it("should keep alive a cell with two live neighbors", () => {
15	    expect(nextGeneration(new Set(["0,0", "0,1", "0,2"]))).toEqual(
16	      new Set(["0,1", "-1,1", "1,1"]),
17	    );
18	  });
19	  it("should keep alive a cell with three live neighbors", () => {
20	    expect(nextGeneration(new Set(["0,0", "0,1", "1,0", "1,1"]))).toEqual(
21	      new Set(["0,0", "0,1", "1,0", "1,1"]),
22	    );
23	  });
24	  it("should kill a cell with four live neighbors (overpopulation)", () => {
25	    expect(
26	      nextGeneration(new Set(["1,1", "0,1", "2,1", "1,0", "1,2"])),
27	    ).toEqual(new Set(["0,1", "2,1", "1,0", "1,2", "0,0", "2,0", "0,2", "2,2"]));
28	  });
29	  it("should bring to life a dead cell with exactly three live neighbors (reproduction)", () => {
30	    expect(nextGeneration(new Set(["0,0", "1,0", "0,1"]))).toEqual(
31	      new Set(["0,0", "1,0", "0,1", "1,1"]),
32	    );
33	  });
34	  it.todo("should handle cells with negative coordinates");
35	});
