1	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1],
5	];
6	
7	const toKey = (x: number, y: number): string => `${x},${y}`;
8	
9	const parseKey = (key: string): [number, number] => {
10	  const [x, y] = key.split(",").map(Number);
11	  return [x, y];
12	};
13	
14	const neighborsOf = (cell: string): string[] => {
15	  const [x, y] = parseKey(cell);
16	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => toKey(x + dx, y + dy));
17	};
18	
19	const cellsToEvaluate = (liveCells: Set<string>): Set<string> => {
20	  const candidates = new Set<string>();
21	  for (const cell of liveCells) {
22	    candidates.add(cell);
23	    for (const neighbor of neighborsOf(cell)) {
24	      candidates.add(neighbor);
25	    }
26	  }
27	  return candidates;
28	};
29	
30	export const nextGeneration = (liveCells: Set<string>): Set<string> => {
31	  const countLiveNeighbors = (cell: string): number =>
32	    neighborsOf(cell).filter((neighbor) => liveCells.has(neighbor)).length;
33	
34	  const nextLiveCells = new Set<string>();
35	  for (const cell of cellsToEvaluate(liveCells)) {
36	    const neighbors = countLiveNeighbors(cell);
37	    const survives = neighbors === 3 || (neighbors === 2 && liveCells.has(cell));
38	    if (survives) {
39	      nextLiveCells.add(cell);
40	    }
41	  }
42	  return nextLiveCells;
43	};
